const config=require("./config");async function testOpenSeaV2(){console.log("🧪 Testing OpenSea API v2 with improved data processing...");const testWallet="0x834711f749fe36dc4a5ae135267b88d0aaad8f3d";try{const apiKey=config.opensea.apiKey;console.log(`🔍 Fetching events for wallet: ${testWallet}`);const response=await fetch(`https://api.opensea.io/api/v2/events/accounts/${testWallet}?event_type=sale&event_type=transfer&event_type=mint&limit=5`,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(response.ok){const data=await response.json();if(console.log(`✅ Found ${data.asset_events?.length||0} events`),data.asset_events&&data.asset_events.length>0){console.log("\n📊 Processing events:");for(let i=0;i<Math.min(2,data.asset_events.length);i++){const event=data.asset_events[i];if(console.log(`\n--- Event ${i+1} ---`),console.log("Full event structure:"),console.log(JSON.stringify(event,null,2)),console.log("\nParsed data:"),console.log(`Type: ${event.event_type}`),console.log(`NFT: ${event.nft?.name||"Unknown"}`),console.log(`Contract: ${event.nft?.contract||"Unknown"}`),console.log(`Token ID: ${event.nft?.identifier||"Unknown"}`),console.log(`Collection: ${event.nft?.collection||"Unknown"}`),console.log(`Chain: ${event.chain||"Unknown"}`),event.payment){if(console.log("Payment data:",JSON.stringify(event.payment,null,2)),event.payment.quantity){const price=parseFloat(event.payment.quantity)/Math.pow(10,event.payment.decimals||18),symbol=event.payment.symbol||"ETH";console.log(`Price from quantity: ${price} ${symbol}`)}if(event.payment.amount){const price=parseFloat(event.payment.amount)/Math.pow(10,event.payment.decimals||18),symbol=event.payment.symbol||"ETH";console.log(`Price from amount: ${price} ${symbol}`)}}else console.log("Payment: N/A");console.log(`Timestamp: ${new Date(1e3*event.event_timestamp).toLocaleString()}`),console.log(`Transaction: ${event.transaction||"N/A"}`),console.log(`Seller: ${event.seller||"Unknown"}`),console.log(`Buyer: ${event.buyer||"Unknown"}`),console.log(`To Address: ${event.to_address||"Unknown"}`)}}else console.log("📭 No events found for this wallet")}else{console.log(`❌ Error: ${response.status} ${response.statusText}`);const errorText=await response.text();console.log(`Error details: ${errorText}`)}}catch(error){console.error("❌ Error:",error.message)}}testOpenSeaV2();